(window.webpackJsonp=window.webpackJsonp||[]).push([[145],{772:function(n,e){n.exports="\x3c!-- \ntitle: 05-CubeIDE\nsort: \n--\x3e \n\n> 图形化开发\n\n## 点灯\n\n1. 进入`.ioc`文件，图形化配置引脚：`PC13->GPIO_Output`\n2. 进入`SYS`菜单，配置烧录模式：\n![配置烧录模式](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2021/image-20210314144921580.png)\n3. `Ctrl+S`保存，自动生成代码。\n4. 在while循环中插入如下代码：\n\n```c\nwhile (1)\n{\n  /* USER CODE END WHILE */\n  HAL_Delay(500);\n  HAL_GPIO_TogglePin(GPIOC, GPIO_PIN_13);\n  /* USER CODE BEGIN 3 */\n}\n```\n\n## 问题\n\n### 无法连接设备\n\n> 首先将boot0短接至3.3\n>\n> 设置sys的Debug模式\n\n![image-20210314144921580](C:\\Users\\44153\\AppData\\Roaming\\Typora\\typora-user-images\\image-20210314144921580.png)\n\n"}}]);